#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <float.h>

#include "kmeans.h"

// CUDA helper macros and functions
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(err)); \
            exit(EXIT_FAILURE); \
        } \
    } while(0)

extern int num_omp_threads; // Defined in main file

// CUDA kernel for finding nearest point and updating partial centers
__global__ void kmeans_iteration_kernel(
    float *feature,      // Flat array: [npoints * nfeatures]
    float *clusters,     // Flat array: [nclusters * nfeatures]
    int *membership,     // [npoints]
    int *partial_new_centers_len, // [nthreads * nclusters]
    float *partial_new_centers,    // Flat: [nthreads * nclusters * nfeatures]
    int npoints,
    int nfeatures,
    int nclusters,
    int nthreads,
    float *delta_ptr)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int tid = blockIdx.y; // Thread ID within the block (simulating omp thread num via block y)

    if (i >= npoints) return;

    // Find nearest cluster
    float min_dist = 3.40282347e+38f; // FLT_MAX
    int index = 0;

    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int f = 0; f < nfeatures; f++) {
            float diff = feature[i * nfeatures + f] - clusters[c * nfeatures + f];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = c;
        }
    }

    // Update membership and delta
    if (membership[i] != index) {
        atomicAdd(delta_ptr, 1.0f);
    }
    membership[i] = index;

    // Update partial centers
    int center_idx = tid * nclusters + index;
    atomicAdd(&partial_new_centers_len[center_idx], 1);

    for (int f = 0; f < nfeatures; f++) {
        atomicAdd(&partial_new_centers[center_idx * nfeatures + f], feature[i * nfeatures + f]);
    }
}

// Host function to aggregate partial results
void aggregate_results(
    int *partial_new_centers_len,
    float *partial_new_centers,
    int *new_centers_len,
    float *new_centers,
    int nclusters,
    int nfeatures,
    int nthreads)
{
    for (int i = 0; i < nclusters; i++) {
        for (int j = 0; j < nthreads; j++) {
            int idx = j * nclusters + i;
            new_centers_len[i] += partial_new_centers_len[idx];
            partial_new_centers_len[idx] = 0;

            for (int k = 0; k < nfeatures; k++) {
                new_centers[i * nfeatures + k] += partial_new_centers[idx * nfeatures + k];
                partial_new_centers[idx * nfeatures + k] = 0.0f;
            }
        }
    }
}

float** kmeans_clustering_cuda(float **feature,    
                          int     nfeatures,
                          int     npoints,
                          int     nclusters,
                          float   threshold,
                          int    *membership) 
{
    int i, j, k, n=0, loop=0;
    int *new_centers_len;			
    float *new_centers;				
    float *clusters_flat;			
    float delta;

    int nthreads = num_omp_threads; 
    if (nthreads == 1) nthreads = 4; // Default to 4 blocks if 1 thread specified for CUDA parallelism

    // Allocate host memory for clusters (2D simulated as 1D for CUDA transfer)
    clusters_flat = (float*) malloc(nclusters * nfeatures * sizeof(float));

    // Initialize clusters from feature data
    for (i=0; i<nclusters; i++) {
        for (j=0; j<nfeatures; j++)
            clusters_flat[i * nfeatures + j] = feature[n][j];
        n++;
    }

    for (i=0; i<npoints; i++)
        membership[i] = -1;

    // Host arrays for aggregation
    new_centers_len = (int*) calloc(nclusters, sizeof(int));
    new_centers = (float*) calloc(nclusters * nfeatures, sizeof(float));

    // CUDA device pointers
    float *d_feature, *d_clusters, *d_partial_centers;
    int *d_membership, *d_partial_len;
    float *d_delta;

    CUDA_CHECK(cudaMalloc(&d_feature, npoints * nfeatures * sizeof(float)));
    CUDA_CHECK(cudaMalloc(&d_clusters, nclusters * nfeatures * sizeof(float)));
    CUDA_CHECK(cudaMalloc(&d_membership, npoints * sizeof(int)));
    CUDA_CHECK(cudaMalloc(&d_partial_len, nthreads * nclusters * sizeof(int)));
    CUDA_CHECK(cudaMalloc(&d_partial_centers, nthreads * nclusters * nfeatures * sizeof(float)));
    CUDA_CHECK(cudaMalloc(&d_delta, sizeof(float)));

    // Copy initial data
    CUDA_CHECK(cudaMemcpy(d_feature, feature[0], npoints * nfeatures * sizeof(float), cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_clusters, clusters_flat, nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_membership, membership, npoints * sizeof(int), cudaMemcpyHostToDevice));

    printf("num of threads = %d (CUDA blocks)\n", nthreads);

    dim3 blockDim(256);
    dim3 dimBlockY(nthreads);
    dim3 dimGrid((npoints + blockDim.x - 1) / blockDim.x, nthreads);

    do {
        delta = 0.0f;
        CUDA_CHECK(cudaMemcpy(d_delta, &delta, sizeof(float), cudaMemcpyHostToDevice));
        CUDA_CHECK(cudaMemset(d_partial_len, 0, nthreads * nclusters * sizeof(int)));
        CUDA_CHECK(cudaMemset(d_partial_centers, 0, nthreads * nclusters * nfeatures * sizeof(float)));

        kmeans_iteration_kernel<<<dimGrid, blockDim>>>(
            d_feature, d_clusters, d_membership,
            d_partial_len, d_partial_centers,
            npoints, nfeatures, nclusters, nthreads, d_delta
        );
        CUDA_CHECK(cudaGetLastError());
        CUDA_CHECK(cudaDeviceSynchronize());

        // Copy partial results back to host
        int *h_partial_len = (int*) malloc(nthreads * nclusters * sizeof(int));
        float *h_partial_centers = (float*) malloc(nthreads * nclusters * nfeatures * sizeof(float));

        CUDA_CHECK(cudaMemcpy(h_partial_len, d_partial_len, nthreads * nclusters * sizeof(int), cudaMemcpyDeviceToHost));
        CUDA_CHECK(cudaMemcpy(h_partial_centers, d_partial_centers, nthreads * nclusters * nfeatures * sizeof(float), cudaMemcpyDeviceToHost));

        // Aggregate on host
        aggregate_results(h_partial_len, h_partial_centers, new_centers_len, new_centers, nclusters, nfeatures, nthreads);

        // Update clusters
        for (i=0; i<nclusters; i++) {
            for (j=0; j<nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters_flat[i * nfeatures + j] = new_centers[i * nfeatures + j] / new_centers_len[i];
                new_centers[i * nfeatures + j] = 0.0f;   
            }
            new_centers_len[i] = 0;   
        }

        // Copy updated clusters to device
        CUDA_CHECK(cudaMemcpy(d_clusters, clusters_flat, nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice));

        // Get delta
        CUDA_CHECK(cudaMemcpy(&delta, d_delta, sizeof(float), cudaMemcpyDeviceToHost));

        free(h_partial_len);
        free(h_partial_centers);

    } while (delta > threshold && loop++ < 500);

    // Copy final membership
    CUDA_CHECK(cudaMemcpy(membership, d_membership, npoints * sizeof(int), cudaMemcpyDeviceToHost));

    // Cleanup CUDA
    cudaFree(d_feature);
    cudaFree(d_clusters);
    cudaFree(d_membership);
    cudaFree(d_partial_len);
    cudaFree(d_partial_centers);
    cudaFree(d_delta);

    // Cleanup host temp
    free(new_centers);
    free(new_centers_len);

    // Convert flat clusters back to 2D array structure expected by caller
    float **clusters_2d = (float**) malloc(nclusters * sizeof(float*));
    clusters_2d[0] = clusters_flat;
    for (i=1; i<nclusters; i++)
        clusters_2d[i] = clusters_2d[i-1] + nfeatures;

    return clusters_2d;
}

int cluster(int      numObjects,      
            int      numAttributes,   
            float  **attributes,                  
            int      nclusters,
            float    threshold,       
            float ***cluster_centres) 
{
    int    *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    srand(7);

    tmp_cluster_centres = kmeans_clustering_cuda(attributes,
                                            numAttributes,
                                            numObjects,
                                            nclusters,
                                            threshold,
                                            membership);      

    if (*cluster_centres) {
		free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}

